/**
 * Internationalization Middleware
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

import { NextRequest, NextResponse } from 'next/server';

const supportedLanguages = ['en', 'ar', 'tr', 'fr', 'de', 'es', 'fa'];

export function middleware(request: NextRequest) {
  const pathname = request.nextUrl.pathname;

  // Skip if already has language or is static file
  if (supportedLanguages.some(lang => pathname.startsWith(`/${lang}`)) ||
      pathname.startsWith('/_next') || 
      pathname.startsWith('/api') ||
      pathname.includes('.')) {
    return;
  }

  // Get default language from cookie or use 'fa' as fallback
  const defaultLanguage = request.cookies.get('defaultLanguage')?.value || 'fa';

  // Redirect root to default language
  if (pathname === '/') {
    return NextResponse.redirect(new URL(`/${defaultLanguage}`, request.url));
  }

  // Redirect other paths to default language
  return NextResponse.redirect(new URL(`/${defaultLanguage}${pathname}`, request.url));
}

export const config = {
  matcher: ['/((?!_next/static|_next/image|favicon.ico).*)'],
};